import{_ as a,o as t,c as d,an as c}from"./chunks/framework.ubcH7j8_.js";const p=JSON.parse('{"title":"Service Naming Decoupling","description":"","frontmatter":{},"headers":[],"relativePath":"ard/CODENAME-DECOUPLING.md","filePath":"ard/CODENAME-DECOUPLING.md","lastUpdated":1773141627000}'),r={name:"ard/CODENAME-DECOUPLING.md"};function o(i,e,l,s,n,m){return t(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="service-naming-decoupling" tabindex="-1">Service Naming Decoupling <a class="header-anchor" href="#service-naming-decoupling" aria-label="Permalink to &quot;Service Naming Decoupling&quot;">​</a></h1><blockquote><p>Status: Implemented Spec folder: <code>specs/014-decouple-service-codenames/</code> Source of truth: <a href="./../../Makefile.html">Makefile</a> and <code>services/*/service.yaml</code></p></blockquote><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Codenames are fun metadata. They are not service identity.</p><p>From this point forward, the platform uses functional service names and <code>arc-*</code> image names as the primary references in:</p><ul><li>architecture docs</li><li>specifications and plans</li><li>config defaults</li><li>wire contracts</li><li>operational runbooks</li><li>service maps</li></ul><p>Codenames may still appear in metadata fields and narrative docs, but only as secondary labels.</p><h2 id="naming-hierarchy" tabindex="-1">Naming Hierarchy <a class="header-anchor" href="#naming-hierarchy" aria-label="Permalink to &quot;Naming Hierarchy&quot;">​</a></h2><p>When there is any ambiguity, use this order:</p><ol><li>Root <a href="./../../Makefile.html">Makefile</a> target name</li><li><code>service.yaml</code> <code>name</code></li><li>GHCR image name</li><li>Service directory under <code>services/</code></li><li><code>codename</code> field</li></ol><h2 id="what-changed" tabindex="-1">What Changed <a class="header-anchor" href="#what-changed" aria-label="Permalink to &quot;What Changed&quot;">​</a></h2><h3 id="primary-references-now-use-service-names" tabindex="-1">Primary references now use service names <a class="header-anchor" href="#primary-references-now-use-service-names" aria-label="Permalink to &quot;Primary references now use service names&quot;">​</a></h3><p>Use:</p><ul><li><code>arc-reasoner</code></li><li><code>arc-messaging</code></li><li><code>arc-streaming</code></li><li><code>arc-cache</code></li><li><code>arc-persistence</code></li><li><code>arc-storage</code></li><li><code>arc-realtime</code></li><li><code>arc-gateway</code></li><li><code>arc-vault</code></li><li><code>arc-flags</code></li><li><code>arc-cortex</code></li><li><code>arc-friday</code></li><li><code>arc-friday-collector</code></li></ul><h3 id="codenames-are-now-secondary-only" tabindex="-1">Codenames are now secondary only <a class="header-anchor" href="#codenames-are-now-secondary-only" aria-label="Permalink to &quot;Codenames are now secondary only&quot;">​</a></h3><p>Allowed:</p><ul><li><code>codename:</code> metadata in <code>service.yaml</code></li><li>optional secondary mention in prose</li><li>sidecar annotations where useful for historical continuity</li></ul><p>Not allowed as primary identifiers:</p><ul><li>package names</li><li>config defaults</li><li>DNS/container assumptions</li><li>NATS subjects</li><li>Pulsar topics</li><li>service maps</li><li>spec titles and main architecture references</li></ul><h2 id="authoritative-service-mapping" tabindex="-1">Authoritative Service Mapping <a class="header-anchor" href="#authoritative-service-mapping" aria-label="Permalink to &quot;Authoritative Service Mapping&quot;">​</a></h2><p>Derived from <a href="./../../Makefile.html">Makefile</a> includes and the current <code>service.yaml</code> files.</p><table tabindex="0"><thead><tr><th>Make target</th><th>Primary runtime name</th><th>Directory</th><th>Image</th><th>Codename metadata</th></tr></thead><tbody><tr><td><code>gateway</code></td><td><code>arc-gateway</code></td><td><code>services/gateway/</code></td><td><code>ghcr.io/arc-framework/arc-gateway:latest</code></td><td>Heimdall</td></tr><tr><td><code>flags</code></td><td><code>arc-flags</code></td><td><code>services/flags/</code></td><td><code>ghcr.io/arc-framework/arc-flags:latest</code></td><td>Mystique</td></tr><tr><td><code>vault</code></td><td><code>arc-vault</code></td><td><code>services/secrets/</code></td><td><code>ghcr.io/arc-framework/arc-vault:latest</code></td><td>Nick Fury</td></tr><tr><td><code>messaging</code></td><td><code>arc-messaging</code></td><td><code>services/messaging/</code></td><td><code>ghcr.io/arc-framework/arc-messaging:latest</code></td><td>Flash</td></tr><tr><td><code>streaming</code></td><td><code>arc-streaming</code></td><td><code>services/streaming/</code></td><td><code>ghcr.io/arc-framework/arc-streaming:latest</code></td><td>Strange</td></tr><tr><td><code>cache</code></td><td><code>arc-cache</code></td><td><code>services/cache/</code></td><td><code>ghcr.io/arc-framework/arc-cache:latest</code></td><td>Sonic</td></tr><tr><td><code>persistence</code></td><td><code>arc-persistence</code></td><td><code>services/persistence/</code></td><td><code>ghcr.io/arc-framework/arc-persistence:latest</code></td><td>Oracle</td></tr><tr><td><code>storage</code></td><td><code>arc-storage</code></td><td><code>services/storage/</code></td><td><code>ghcr.io/arc-framework/arc-storage:latest</code></td><td>Tardis</td></tr><tr><td><code>realtime</code></td><td><code>arc-realtime</code></td><td><code>services/realtime/</code></td><td><code>ghcr.io/arc-framework/arc-realtime:latest</code></td><td>Daredevil</td></tr><tr><td><code>reasoner</code></td><td><code>arc-reasoner</code></td><td><code>services/reasoner/</code></td><td><code>ghcr.io/arc-framework/arc-reasoner:latest</code></td><td>Sherlock</td></tr><tr><td><code>cortex</code></td><td><code>arc-cortex</code></td><td><code>services/cortex/</code></td><td><code>ghcr.io/arc-framework/arc-cortex:latest</code></td><td>Cortex</td></tr><tr><td><code>otel</code></td><td><code>arc-friday</code></td><td><code>services/otel/</code></td><td><code>ghcr.io/arc-framework/arc-friday:latest</code></td><td>Friday</td></tr><tr><td><code>friday-collector</code></td><td><code>arc-friday-collector</code></td><td><code>services/otel/</code></td><td><code>ghcr.io/arc-framework/arc-friday-collector:latest</code></td><td>Friday Collector</td></tr></tbody></table><h2 id="planned-services" tabindex="-1">Planned Services <a class="header-anchor" href="#planned-services" aria-label="Permalink to &quot;Planned Services&quot;">​</a></h2><p>Planned services should be documented, but they must not be mixed into the authoritative runtime map until they exist in <a href="./../../Makefile.html">Makefile</a> or have a concrete <code>service.yaml</code>.</p><p>Use a separate planned section for items such as:</p><ul><li><code>arc-voice-agent</code></li><li><code>arc-guard</code></li><li><code>arc-critic</code></li><li><code>arc-gym</code></li><li><code>arc-billing</code></li><li><code>arc-db-vector</code></li><li><code>arc-identity</code></li><li><code>arc-chaos</code></li></ul><p>That keeps documentation honest:</p><ul><li><strong>implemented</strong> = operable now</li><li><strong>planned</strong> = architectural intent</li></ul><h2 id="realtime-sidecars" tabindex="-1">Realtime Sidecars <a class="header-anchor" href="#realtime-sidecars" aria-label="Permalink to &quot;Realtime Sidecars&quot;">​</a></h2><p>The <code>realtime</code> target is the operator-facing unit, but the runtime stack also includes:</p><table tabindex="0"><thead><tr><th>Runtime service</th><th>Image</th><th>Purpose</th><th>Codename metadata</th></tr></thead><tbody><tr><td><code>arc-realtime-ingress</code></td><td><code>ghcr.io/arc-framework/arc-realtime-ingress:latest</code></td><td>RTMP ingest</td><td>Sentry</td></tr><tr><td><code>arc-realtime-egress</code></td><td><code>ghcr.io/arc-framework/arc-realtime-egress:latest</code></td><td>Recording/export</td><td>Scribe</td></tr></tbody></table><h2 id="operational-guidance" tabindex="-1">Operational Guidance <a class="header-anchor" href="#operational-guidance" aria-label="Permalink to &quot;Operational Guidance&quot;">​</a></h2><p>Prefer these forms in all new docs:</p><ul><li><code>arc-reasoner</code> instead of a codename-first label</li><li><code>arc-messaging</code> instead of a codename-first label</li><li><code>arc-streaming</code> instead of a codename-first label</li><li><code>arc-cache</code> instead of a codename-first label</li><li><code>arc-realtime</code> instead of a codename-first label</li></ul><p>If a codename is included for readability, format it as secondary metadata, for example:</p><p><code>arc-reasoner</code> (codename: Sherlock)</p><p>Not the other way around.</p><h2 id="impact" tabindex="-1">Impact <a class="header-anchor" href="#impact" aria-label="Permalink to &quot;Impact&quot;">​</a></h2><p>This keeps naming stable across:</p><ul><li>implementation</li><li>deployment</li><li>contracts</li><li>diagrams</li><li>future service additions</li></ul><p>It also removes the mismatch between historical codename-heavy docs and the actual operational model exposed by <a href="./../../Makefile.html">Makefile</a>.</p>',41)])])}const u=a(r,[["render",o]]);export{p as __pageData,u as default};
